document.addEventListener("DOMContentLoaded",()=>{document.querySelectorAll(".copy-link-button").forEach((button)=>{button.addEventListener("click",async()=>{const link=button.dataset.copyLink||window.location.href;const originalText=button.textContent;try{await navigator.clipboard.writeText(link);button.textContent="Link copied ✓";}catch(error){const temporaryInput=document.createElement("textarea");temporaryInput.value=link;temporaryInput.setAttribute("readonly","");temporaryInput.style.position="fixed";temporaryInput.style.opacity="0";document.body.appendChild(temporaryInput);temporaryInput.select();document.execCommand("copy");temporaryInput.remove();button.textContent="Link copied ✓";}
window.setTimeout(()=>{button.textContent=originalText;},2200);});});});